package com.babidndn.common;
import com.babidndn.category.*;import com.babidndn.menu.*;import org.springframework.boot.CommandLineRunner;import org.springframework.stereotype.Component;
@Component public class DataInitializer implements CommandLineRunner { private final CategoryRepository categories; private final MenuRepository menus; public DataInitializer(CategoryRepository categories,MenuRepository menus){this.categories=categories;this.menus=menus;} public void run(String... args){ if(categories.count()>0) return; Category basic=categories.save(new Category("기본 컵밥")); Category premium=categories.save(new Category("프리미엄")); Category side=categories.save(new Category("토핑/사이드")); Category drink=categories.save(new Category("음료")); menus.save(new Menu("제육 컵밥",5500,basic,"매콤한 제육볶음과 밥",null,false)); menus.save(new Menu("스팸마요 컵밥",6000,premium,"스팸, 마요, 김가루 조합",null,false)); menus.save(new Menu("계란 추가",1000,side,"든든한 반숙 계란 토핑",null,false)); menus.save(new Menu("콜라",1500,drink,"시원한 캔 음료",null,false)); } }
